INSERT INTO educational_institution_accreditation.criterias
(id, standard_id, name)
VALUES
-- Tiêu chuẩn 1
('1.1', '1', 'Lãnh đạo CSGD đảm bảo tầm nhìn và sứ mạng của CSGD đáp ứng được nhu cầu và sự hài lòng của các bên liên quan.'),
('1.2', '1', 'Lãnh đạo CSGD thúc đẩy các giá trị văn hóa phù hợp với tầm nhìn và sứ mạng của CSGD.'),
('1.3', '1', 'Tầm nhìn, sứ mạng và văn hóa của CSGD được phổ biến, quán triệt và giải thích rõ ràng để thực hiện.'),
('1.4', '1', 'Tầm nhìn, sứ mạng và văn hóa của CSGD được rà soát để đáp ứng nhu cầu và sự hài lòng của các bên liên quan.'),
('1.5', '1', 'Tầm nhìn, sứ mạng và văn hóa của CSGD cũng như quá trình xây dựng và phát triển chúng được cải tiến để đáp ứng nhu cầu và sự hài lòng của các bên liên quan.'),
-- Tiêu chuẩn 2
('2.1', '2', 'Hệ thống quản trị (bao gồm hội đồng quản trị hoặc hội đồng trường; các tổ chức đảng, đoàn thể; các hội đồng tư vấn khác) được thành lập theo quy định của pháp luật nhằm thiết lập định hướng chiến lược phù hợp với bối cảnh cụ thể của CSGD; đảm bảo trách nhiệm giải trình, tính bền vững, sự minh bạch và giảm thiểu các rủi ro tiềm tàng trong quá trình quản trị của CSGD.'),
('2.2', '2', 'Quyết định của các cơ quan quản trị được chuyển tải thành các kế hoạch hành động, chính sách, hướng dẫn để triển khai thực hiện.'),
('2.3', '2', 'Hệ thống quản trị của CSGD được rà soát thường xuyên.'),
('2.4', '2', 'Hệ thống quản trị của CSGD được cải tiến để tăng hiệu quả hoạt động của CSGD và quản lý rủi ro tốt hơn.'),
-- Tiêu chuẩn 3
('3.1', '3', 'Lãnh đạo CSGD thiết lập cơ cấu quản lý trong đó phân định rõ vai trò, trách nhiệm, quá trình ra quyết định, chế độ thông tin, báo cáo để đạt được tầm nhìn, sứ mạng, văn hóa và các mục tiêu chiến lược của CSGD.'),
('3.2', '3', 'Lãnh đạo CSGD tham gia vào việc thông tin, kết nối các bên liên quan để định hướng tầm nhìn, sứ mạng, văn hóa và các mục tiêu chiến lược của CSGD.'),
('3.3', '3', 'Cơ cấu lãnh đạo và quản lý của CSGD được rà soát thường xuyên.'),
('3.4', '3', 'Cơ cấu lãnh đạo và quản lý của CSGD được cải tiến nhằm tăng hiệu quả quản lý và đạt được hiệu quả công việc của CSGD như mong muốn.'),
-- Tiêu chuẩn 4
('4.1', '4', 'Thực hiện việc lập kế hoạch chiến lược nhằm đạt được tầm nhìn, sứ mạng và văn hóa cũng như các mục tiêu chiến lược trong đào tạo, NCKH và phục vụ cộng đồng.'),
('4.2', '4', 'Kế hoạch chiến lược được quán triệt và chuyển tải thành các kế hoạch ngắn hạn và dài hạn để triển khai thực hiện.'),
('4.3', '4', 'Các chỉ số thực hiện chính, các chỉ tiêu phấn đấu chính được thiết lập để đo lường mức độ thực hiện các mục tiêu chiến lược của CSGD.'),
('4.4', '4', 'Quá trình lập kế hoạch chiến lược cũng như các chỉ số thực hiện chính, các chỉ tiêu phấn đấu chính được cải tiến để đạt được các mục tiêu chiến lược của CSGD.'),
-- Tiêu chuẩn 5
('5.1', '5', 'Có hệ thống để xây dựng các chính sách về đào tạo, NCKH và phục vụ cộng đồng.'),
('5.2', '5', 'Quy trình giám sát sự tuân thủ các chính sách được cụ thể hóa bằng văn bản, phổ biến và thực hiện.'),
('5.3', '5', 'Các chính sách về đào tạo, NCKH và phục vụ cộng đồng được rà soát thường xuyên.'),
('5.4', '5', 'Các chính sách về đào tạo, NCKH và phục vụ cộng đồng được cải tiến nhằm tăng hiệu quả hoạt động của CSGD, đáp ứng nhu cầu và sự hài lòng của các bên liên quan.'),
-- Tiêu chuẩn 6: Nguồn nhân lực
('6.1', '6', 'Nguồn nhân lực được quy hoạch để đáp ứng đầy đủ nhu cầu của hoạt động đào tạo, NCKH và phục vụ cộng đồng.'),
('6.2', '6', 'Các tiêu chí tuyển dụng và lựa chọn, bao gồm cả các tiêu chí về đạo đức và tự do học thuật, được sử dụng trong việc đề bạt, bổ nhiệm và sắp xếp nhân sự, được xác định và phổ biến.'),
('6.3', '6', 'Tiêu chuẩn năng lực, bao gồm cả kỹ năng lãnh đạo, của các nhóm cán bộ, giảng viên và nhân viên khác nhau được xác định và xây dựng.'),
('6.4', '6', 'Nhu cầu đào tạo, bồi dưỡng và phát triển đội ngũ cán bộ, giảng viên, nhân viên được xác định và có các hoạt động được triển khai để đáp ứng các nhu cầu đó.'),
('6.5', '6', 'Hệ thống quản lý việc thực hiện nhiệm vụ, bao gồm chế độ khen thưởng, ghi nhận và kế hoạch bồi dưỡng, được triển khai để thúc đẩy và hỗ trợ hoạt động đào tạo, NCKH và phục vụ cộng đồng.'),
('6.6', '6', 'Các chế độ, chính sách, quy trình và quy hoạch về nguồn nhân lực được rà soát thường xuyên.'),
('6.7', '6', 'Các chế độ, chính sách, quy trình và quy hoạch về nguồn nhân lực được cải tiến để hỗ trợ đào tạo, NCKH và phục vụ cộng đồng.'),
-- Tiêu chuẩn 7: Tài chính và cơ sở vật chất
('7.1', '7', 'Hệ thống lập kế hoạch, triển khai, kiểm toán và tăng cường các nguồn lực tài chính của CSGD được thiết lập và vận hành nhằm hỗ trợ thực hiện tầm nhìn, sứ mạng và các mục tiêu chiến lược trong đào tạo, NCKH và phục vụ cộng đồng.'),
('7.2', '7', 'Hệ thống lập kế hoạch, bảo trì, đánh giá và nâng cấp cơ sở vật chất, cơ sở hạ tầng như phương tiện dạy và học, phòng thí nghiệm, thiết bị và công cụ được thiết lập và vận hành để đáp ứng các nhu cầu về đào tạo, NCKH và phục vụ cộng đồng.'),
('7.3', '7', 'Hệ thống lập kế hoạch, bảo trì, kiểm toán và nâng cấp các thiết bị công nghệ thông tin và cơ sở hạ tầng như máy tính, hệ thống mạng, hệ thống dự phòng, bảo mật và quyền truy cập được thiết lập và vận hành để đáp ứng các nhu cầu về đào tạo, NCKH và phục vụ cộng đồng.'),
('7.4', '7', 'Hệ thống lập kế hoạch, bảo trì, đánh giá và tăng cường các nguồn lực học tập như nguồn học liệu thư viện, thiết bị hỗ trợ giảng dạy và cơ sở dữ liệu trực tuyến được thiết lập và vận hành để đáp ứng các nhu cầu về đào tạo, NCKH và phục vụ cộng đồng.'),
('7.5', '7', 'Hệ thống lập kế hoạch, thực hiện, đánh giá và cải tiến môi trường, sức khỏe, an toàn và khả năng tiếp cận của những người có nhu cầu đặc biệt được thiết lập và vận hành.'),
-- Tiêu chuẩn 8: Quan hệ đối ngoại
('8.1', '8', 'Có kế hoạch phát triển các đối tác, mạng lưới và quan hệ đối ngoại để đạt được tầm nhìn, sứ mạng và các mục tiêu chiến lược của CSGD.'),
('8.2', '8', 'Các chính sách, quy trình và thỏa thuận nhằm thúc đẩy các đối tác, mạng lưới và quan hệ đối ngoại được triển khai thực hiện.'),
('8.3', '8', 'Các đối tác, mạng lưới và quan hệ đối ngoại được rà soát.'),
('8.4', '8', 'Các đối tác, mạng lưới và quan hệ đối ngoại được cải thiện để đạt được tầm nhìn, sứ mạng và các mục tiêu chiến lược của CSGD.'),
-- Tiêu chuẩn 9: Đảm bảo chất lượng bên trong
('9.1', '9', 'Cơ cấu, vai trò, trách nhiệm và trách nhiệm giải trình của hệ thống đảm bảo chất lượng bên trong được thiết lập nhằm đáp ứng các mục tiêu chiến lược và mục tiêu đảm bảo chất lượng của CSGD.'),
('9.2', '9', 'Kế hoạch chiến lược về đảm bảo chất lượng, bao gồm chiến lược, chính sách, sự tham gia của các bên liên quan và các hoạt động như thúc đẩy công tác đảm bảo chất lượng và tập huấn nâng cao năng lực, được xây dựng để đáp ứng các mục tiêu chiến lược và đảm bảo chất lượng của CSGD.'),
('9.3', '9', 'Kế hoạch chiến lược về đảm bảo chất lượng được quán triệt và chuyển tải thành các kế hoạch ngắn hạn và dài hạn để triển khai thực hiện.'),
('9.4', '9', 'Hệ thống lưu trữ văn bản, rà soát và phổ biến các chính sách, hệ thống, quy trình và thủ tục đảm bảo chất lượng được triển khai.'),
('9.5', '9', 'Các chỉ số thực hiện chính và các chỉ tiêu phấn đấu chính được thiết lập để đo lường kết quả công tác đảm bảo chất lượng của CSGD.'),
('9.6', '9', 'Quy trình lập kế hoạch, các chỉ số thực hiện chính và các chỉ tiêu phấn đấu chính được cải tiến để đáp ứng các mục tiêu chiến lược và đảm bảo chất lượng của CSGD.'),
-- Tiêu chuẩn 10: Tự đánh giá và đánh giá ngoài
('10.1', '10', 'Kế hoạch tự đánh giá và chuẩn bị cho việc đánh giá ngoài được thiết lập.'),
('10.2', '10', 'Việc tự đánh giá và đánh giá ngoài được thực hiện định kỳ bởi các cán bộ và/hoặc các chuyên gia độc lập đã được đào tạo.'),
('10.3', '10', 'Các phát hiện và kết quả của việc tự đánh giá và đánh giá ngoài được rà soát.'),
('10.4', '10', 'Quy trình tự đánh giá và quy trình chuẩn bị cho việc đánh giá ngoài được cải tiến để đáp ứng các mục tiêu chiến lược của CSGD.'),
-- Tiêu chuẩn 11: Quản lý thông tin ĐBCL bên trong
('11.1', '11', 'Kế hoạch quản lý thông tin ĐBCL bên trong bao gồm việc thu thập, xử lý, báo cáo, nhận và chuyển thông tin từ các bên liên quan nhằm hỗ trợ hoạt động đào tạo, NCKH và phục vụ cộng đồng được thiết lập.'),
('11.2', '11', 'Thông tin về ĐBCL bên trong bao gồm kết quả phân tích dữ liệu phải phù hợp, chính xác và sẵn có để cung cấp kịp thời cho các bên liên quan nhằm hỗ trợ cho việc ra quyết định; đồng thời, đảm bảo sự thống nhất, bảo mật và an toàn.'),
('11.3', '11', 'Thực hiện rà soát hệ thống quản lý thông tin ĐBCL bên trong, số lượng, chất lượng, sự thống nhất, bảo mật, an toàn của dữ liệu và thông tin.'),
('11.4', '11', 'Việc quản lý thông tin ĐBCL bên trong cũng như các chính sách, quy trình và kế hoạch quản lý thông tin ĐBCL bên trong được cải tiến để hỗ trợ đào tạo, NCKH và phục vụ cộng đồng.'),

-- Tiêu chuẩn 12: Nâng cao chất lượng
('12.1', '12', 'Xây dựng kế hoạch liên tục nâng cao chất lượng của CSGD bao gồm các chính sách, hệ thống, quy trình, thủ tục và nguồn lực để thực hiện tốt nhất hoạt động đào tạo, NCKH và phục vụ cộng đồng.'),
('12.2', '12', 'Các tiêu chí lựa chọn đối tác, các thông tin so chuẩn và đối sánh để nâng cao chất lượng hoạt động được thiết lập.'),
('12.3', '12', 'Thực hiện việc so chuẩn và đối sánh nhằm tăng cường các hoạt động ĐBCL và khuyến khích đổi mới, sáng tạo.'),
('12.4', '12', 'Quy trình lựa chọn, sử dụng các thông tin so chuẩn và đối sánh được rà soát.'),
('12.5', '12', 'Quy trình lựa chọn, sử dụng các thông tin so chuẩn và đối sánh được cải tiến để liên tục đạt được các kết quả tốt nhất trong đào tạo, NCKH và phục vụ cộng đồng.'),

-- Tiêu chuẩn 13: Tuyển sinh và nhập học
('13.1', '13', 'Xây dựng kế hoạch, chính sách và truyền thông để tuyển sinh cho các CTĐT khác nhau của CSGD.'),
('13.2', '13', 'Xây dựng các tiêu chí để lựa chọn người học có chất lượng cho mỗi CTĐT.'),
('13.3', '13', 'Có quy trình giám sát công tác tuyển sinh và nhập học.'),
('13.4', '13', 'Có các biện pháp giám sát việc tuyển sinh và nhập học.'),
('13.5', '13', 'Công tác tuyển sinh và nhập học được cải tiến để đảm bảo tính phù hợp và hiệu quả.'),

-- Tiêu chuẩn 14: Thiết kế và rà soát chương trình dạy học
('14.1', '14', 'Xây dựng hệ thống để thiết kế, phát triển, giám sát, rà soát, thẩm định, phê duyệt và ban hành các chương trình dạy học cho tất cả các CTĐT và các môn học/học phần có sự đóng góp và phản hồi của các bên liên quan.'),
('14.2', '14', 'Có hệ thống xây dựng, rà soát, điều chỉnh CĐR của CTĐT và các môn học/học phần để phù hợp với nhu cầu của các bên liên quan.'),
('14.3', '14', 'Các đề cương môn học/học phần, kế hoạch giảng dạy của CTĐT và các môn học/học phần được văn bản hóa, phổ biến và thực hiện dựa trên CĐR.'),
('14.4', '14', 'Việc rà soát quy trình thiết kế, đánh giá và rà soát chương trình dạy học được thực hiện.'),
('14.5', '14', 'Quy trình thiết kế, đánh giá và chương trình dạy học được cải tiến để đảm bảo sự phù hợp và cập nhật nhằm đáp ứng nhu cầu luôn thay đổi của các bên liên quan.'),

-- Tiêu chuẩn 15: Dạy và học
('15.1', '15', 'Thiết lập được hệ thống lựa chọn các hoạt động dạy và học phù hợp với triết lý giáo dục và để đạt được CĐR.'),
('15.2', '15', 'Triển khai được hệ thống thu hút, tuyển chọn đội ngũ GV, phân công nhiệm vụ dựa trên trình độ chuyên môn, năng lực, thành tích chuyên môn và kinh nghiệm.'),
('15.3', '15', 'Các hoạt động dạy và học thúc đẩy việc học tập suốt đời được tổ chức phù hợp để đạt được CĐR.'),
('15.4', '15', 'Các hoạt động dạy và học được giám sát và đánh giá để đảm bảo và cải tiến chất lượng.'),
('15.5', '15', 'Triết lý giáo dục cũng như hoạt động dạy và học được cải tiến để đạt được CĐR, đảm bảo dạy và học có chất lượng, học tập suốt đời.'),
-- Tiêu chuẩn 16: Đánh giá người học
('16.1', '16', 'Thiết lập được hệ thống lập kế hoạch và lựa chọn các loại hình đánh giá NH phù hợp trong quá trình học tập.'),
('16.2', '16', 'Các hoạt động đánh giá NH được thiết kế phù hợp với việc đạt được CĐR.'),
('16.3', '16', 'Các phương pháp đánh giá và kết quả đánh giá NH được rà soát để đảm bảo độ chính xác, tin cậy, công bằng và hướng tới đạt được CĐR.'),
('16.4', '16', 'Các loại hình và các phương pháp đánh giá NH được cải tiến để đảm bảo độ chính xác, tin cậy và hướng tới đạt được CĐR.'),

-- Tiêu chuẩn 17: Phục vụ và hỗ trợ người học
('17.1', '17', 'Có kế hoạch triển khai các hoạt động phục vụ và hỗ trợ NH cũng như hệ thống giám sát NH.'),
('17.2', '17', 'Các hoạt động phục vụ và hỗ trợ NH cũng như hệ thống giám sát NH được triển khai để đáp ứng nhu cầu của các bên liên quan.'),
('17.3', '17', 'Các hoạt động phục vụ và hỗ trợ NH cũng như hệ thống giám sát NH được rà soát.'),
('17.4', '17', 'Các hoạt động phục vụ và hỗ trợ NH cũng như hệ thống giám sát NH được cải tiến để đáp ứng nhu cầu và sự hài lòng của các bên liên quan.'),

-- Tiêu chuẩn 18: Quản lý hoạt động nghiên cứu
('18.1', '18', 'Thiết lập được hệ thống chỉ đạo, điều hành, thực hiện, giám sát và rà soát các hoạt động nghiên cứu, chất lượng cán bộ nghiên cứu, các nguồn lực và các hoạt động liên quan đến nghiên cứu.'),
('18.2', '18', 'Chiến lược tìm kiếm nguồn kinh phí phục vụ nghiên cứu, thúc đẩy nghiên cứu, phát kiến khoa học, hợp tác và nghiên cứu đỉnh cao được triển khai để đạt được tầm nhìn và sứ mạng của CSGD.'),
('18.3', '18', 'Các chỉ số thực hiện chính được sử dụng để đánh giá số lượng và chất lượng nghiên cứu.'),
('18.4', '18', 'Công tác quản lý nghiên cứu được cải tiến để nâng cao chất lượng nghiên cứu và phát kiến khoa học.'),

-- Tiêu chuẩn 19: Quản lý tài sản trí tuệ
('19.1', '19', 'Thiết lập được hệ thống quản lý và bảo hộ các phát minh, sáng chế, bản quyền và kết quả nghiên cứu.'),
('19.2', '19', 'Hệ thống ghi nhận, lưu trữ và khai thác tài sản trí tuệ được triển khai.'),
('19.3', '19', 'Hệ thống rà soát công tác quản lý tài sản trí tuệ được triển khai thực hiện.'),
('19.4', '19', 'Công tác quản lý tài sản trí tuệ được cải tiến để bảo hộ CSGD, cán bộ nghiên cứu và các lợi ích cộng đồng.'),

-- Tiêu chuẩn 20: Hợp tác và đối tác nghiên cứu
('20.1', '20', 'Xây dựng hệ thống để thiết lập các mối quan hệ hợp tác và đối tác trong nghiên cứu nhằm đáp ứng các mục tiêu nghiên cứu.'),
('20.2', '20', 'Triển khai được các chính sách và quy trình thúc đẩy hợp tác và đối tác nghiên cứu.'),
('20.3', '20', 'Hệ thống rà soát tính hiệu quả của hợp tác và đối tác nghiên cứu được triển khai thực hiện.'),
('20.4', '20', 'Các hoạt động hợp tác và đối tác nghiên cứu được cải thiện để đạt được các mục tiêu nghiên cứu.'),
-- Tiêu chuẩn 21: Kết nối và phục vụ cộng đồng
('21.1', '21', 'Xây dựng được kế hoạch kết nối và cung cấp các dịch vụ phục vụ cộng đồng để thực hiện tầm nhìn và sứ mạng của CSGD.'),
('21.2', '21', 'Các chính sách và hướng dẫn cho hoạt động kết nối và phục vụ cộng đồng được thực hiện.'),
('21.3', '21', 'Triển khai được hệ thống đo lường, giám sát việc kết nối và phục vụ cộng đồng.'),
('21.4', '21', 'Việc cung cấp các dịch vụ phục vụ và kết nối cộng đồng được cải tiến để đáp ứng nhu cầu và sự hài lòng của các bên liên quan.'),

-- Tiêu chuẩn 22: Kết quả đào tạo
('22.1', '22', 'Tỷ lệ NH đạt yêu cầu và tỷ lệ thôi học của tất cả các CTĐT, các môn học/học phần được xác lập, giám sát và đối sánh để cải tiến.'),
('22.2', '22', 'Thời gian tốt nghiệp trung bình cho tất cả các CTĐT được xác lập, giám sát và đối sánh để cải tiến.'),
('22.3', '22', 'Khả năng có việc làm của NH tốt nghiệp của tất cả các CTĐT được xác lập, giám sát và đối sánh để cải tiến.'),
('22.4', '22', 'Mức độ hài lòng của các bên liên quan về chất lượng của NH tốt nghiệp được xác lập, giám sát và đối sánh để cải tiến.'),

-- Tiêu chuẩn 23: Kết quả nghiên cứu
('23.1', '23', 'Loại hình và khối lượng nghiên cứu của đội ngũ GV và cán bộ nghiên cứu được xác lập, giám sát và đối sánh để cải tiến.'),
('23.2', '23', 'Loại hình và khối lượng nghiên cứu của NH được xác lập, giám sát và đối sánh để cải tiến.'),
('23.3', '23', 'Loại hình và số lượng các công bố khoa học bao gồm cả các trích dẫn được xác lập, giám sát và đối sánh để cải tiến.'),
('23.4', '23', 'Loại hình và số lượng các tài sản trí tuệ được xác lập, giám sát và đối sánh để cải tiến.'),
('23.5', '23', 'Ngân quỹ cho từng loại hoạt động nghiên cứu được xác lập, giám sát và đối sánh để cải tiến.'),
('23.6', '23', 'Kết quả nghiên cứu và sáng tạo (bao gồm cả việc thương mại hóa, thử nghiệm chuyển giao, thành lập các đơn vị khởi nghiệp) được xác lập, giám sát và đối sánh để cải tiến.'),

-- Tiêu chuẩn 24: Kết quả phục vụ cộng đồng
('24.1', '24', 'Loại hình và khối lượng tham gia vào hoạt động kết nối và phục vụ cộng đồng, đóng góp cho xã hội được xác lập, giám sát và đối sánh để cải tiến.'),
('24.2', '24', 'Tác động xã hội, kết quả của hoạt động kết nối và phục vụ cộng đồng, đóng góp cho xã hội được xác lập, giám sát và đối sánh để cải tiến.'),
('24.3', '24', 'Tác động của hoạt động kết nối và phục vụ cộng đồng đối với NH và đội ngũ cán bộ, GV, nhân viên được xác lập, giám sát và đối sánh để cải tiến.'),
('24.4', '24', 'Sự hài lòng của các bên liên quan về hoạt động kết nối và phục vụ cộng đồng, đóng góp cho xã hội được xác lập, giám sát và đối sánh để cải tiến.'),

-- Tiêu chuẩn 25: Kết quả tài chính và thị trường
('25.1', '25', 'Kết quả và các chỉ số tài chính của hoạt động đào tạo, NCKH và phục vụ cộng đồng được xác lập, giám sát và đối sánh để cải tiến.'),
('25.2', '25', 'Kết quả và các chỉ số thị trường của hoạt động đào tạo, NCKH và phục vụ cộng đồng được xác lập, giám sát và đối sánh để cải tiến.');